module multiplexer_4to1 (
    input [1:0] sel,
    input [3:0] obf_in,
    output reg out
);

    always @(sel or obf_in) begin
        case (sel)
            2'b00: out = obf_in[0];
            2'b01: out = obf_in[1];
            2'b10: out = obf_in[2];
            2'b11: out = obf_in[3];
            default: out = 0;
        endcase
    end

endmodule
